/**
 * Unit tests for prompt/handoff-injector hook
 *
 * Tests the READ half of the save/restore loop:
 * - No-op when HANDOFF.md is absent
 * - No-op when HANDOFF.md is stale (> 24 hours old)
 * - No-op when HANDOFF.md content is too short
 * - Injects content via outputPromptContext on first prompt
 * - Renames file to HANDOFF.md.consumed after injection
 * - Token budget truncation when content exceeds MAX_TOKENS
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
    outputPromptContext: vi.fn((msg: string) => ({
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: { additionalContext: msg, hookEventName: 'UserPromptSubmit' },
    })),
    getProjectDir: vi.fn(() => '/test/project'),
    estimateTokenCount: vi.fn((text: string) => Math.ceil(text.length / 3)),
  };
});

const mockExistsSync = vi.fn();
const mockReadFileSync = vi.fn();
const mockRenameSync = vi.fn();
const mockStatSync = vi.fn();

vi.mock('node:fs', () => ({
  existsSync: (...args: unknown[]) => mockExistsSync(...args),
  readFileSync: (...args: unknown[]) => mockReadFileSync(...args),
  renameSync: (...args: unknown[]) => mockRenameSync(...args),
  statSync: (...args: unknown[]) => mockStatSync(...args),
}));

import { handoffInjector } from '../../prompt/handoff-injector.js';
import { outputSilentSuccess, outputPromptContext } from '../../lib/common.js';
import { createTestContext } from '../fixtures/test-context.js';

// ---------------------------------------------------------------------------
// Constants matching the hook's internal values
// ---------------------------------------------------------------------------

const MAX_AGE_MS = 24 * 60 * 60 * 1000;
const MAX_TOKENS = 600;
const MAX_CHARS = MAX_TOKENS * 3; // ~1800 chars

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createPromptInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'UserPromptSubmit',
    tool_name: '',
    session_id: 'test-prompt-session-001',
    tool_input: {},
    project_dir: '/test/project',
    ...overrides,
  };
}

const HANDOFF_PATH = '/test/project/.claude/HANDOFF.md';
const CONSUMED_PATH = '/test/project/.claude/HANDOFF.md.consumed';

const VALID_HANDOFF_CONTENT = `# Session Handoff

**Branch**: feat/my-feature
**When**: 2026-03-02 10:00:00 UTC
**Session**: session-abc

## Summary
I fixed the authentication bug by updating the JWT validation logic.

## Modified Files
- src/auth/jwt.ts
- tests/auth.test.ts
`;

function mockFreshHandoff(content = VALID_HANDOFF_CONTENT) {
  mockExistsSync.mockImplementation((p: string) => p === HANDOFF_PATH);
  mockStatSync.mockReturnValue({ mtimeMs: Date.now() - 1000 }); // 1 second old
  mockReadFileSync.mockReturnValue(content);
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

let testCtx: ReturnType<typeof createTestContext>;
describe('prompt/handoff-injector', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
    mockExistsSync.mockReturnValue(false);
  });

  // -------------------------------------------------------------------------
  // No-op paths
  // -------------------------------------------------------------------------

  describe('no-op when HANDOFF.md is absent', () => {
    it('returns silent success when file does not exist', () => {
      mockExistsSync.mockReturnValue(false);
      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
      expect(outputSilentSuccess).toHaveBeenCalled();
      expect(outputPromptContext).not.toHaveBeenCalled();
    });

    it('logs "No HANDOFF.md found" when absent', () => {
      mockExistsSync.mockReturnValue(false);
      const input = createPromptInput();
      handoffInjector(input, testCtx);

      expect(testCtx.log).toHaveBeenCalledWith(
        'handoff-injector',
        expect.stringContaining('No HANDOFF.md'),
      );
    });
  });

  describe('no-op when HANDOFF.md is stale (> 24h)', () => {
    it('returns silent success when file is older than 24 hours', () => {
      mockExistsSync.mockImplementation((p: string) => p === HANDOFF_PATH);
      mockStatSync.mockReturnValue({ mtimeMs: Date.now() - MAX_AGE_MS - 1 });

      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
      expect(outputSilentSuccess).toHaveBeenCalled();
      expect(mockReadFileSync).not.toHaveBeenCalled();
    });

    it('logs stale age in hours', () => {
      mockExistsSync.mockImplementation((p: string) => p === HANDOFF_PATH);
      mockStatSync.mockReturnValue({ mtimeMs: Date.now() - 30 * 3600 * 1000 }); // 30 hours ago

      const input = createPromptInput();
      handoffInjector(input, testCtx);

      expect(testCtx.log).toHaveBeenCalledWith(
        'handoff-injector',
        expect.stringContaining('> 24h'),
      );
    });

    it('returns silent success when statSync throws', () => {
      mockExistsSync.mockImplementation((p: string) => p === HANDOFF_PATH);
      mockStatSync.mockImplementation(() => { throw new Error('EACCES'); });

      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
      expect(outputSilentSuccess).toHaveBeenCalled();
    });
  });

  describe('no-op when content is too short', () => {
    it('returns silent success when content is empty', () => {
      mockFreshHandoff('');
      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
      expect(outputSilentSuccess).toHaveBeenCalled();
    });

    it('returns silent success when content is < 20 chars after trim', () => {
      mockFreshHandoff('Short.');
      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
      expect(outputSilentSuccess).toHaveBeenCalled();
    });

    it('returns silent success when readFileSync throws', () => {
      mockExistsSync.mockImplementation((p: string) => p === HANDOFF_PATH);
      mockStatSync.mockReturnValue({ mtimeMs: Date.now() - 1000 });
      mockReadFileSync.mockImplementation(() => { throw new Error('EPERM'); });

      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
    });
  });

  // -------------------------------------------------------------------------
  // Injection behavior
  // -------------------------------------------------------------------------

  describe('context injection', () => {
    it('calls outputPromptContext with HANDOFF.md content', () => {
      mockFreshHandoff();
      const input = createPromptInput();
      handoffInjector(input, testCtx);

      expect(outputPromptContext).toHaveBeenCalled();
    });

    it('injected context includes [Previous Session Handoff] marker', () => {
      mockFreshHandoff();
      const input = createPromptInput();
      handoffInjector(input, testCtx);

      const injected = vi.mocked(outputPromptContext).mock.calls[0][0];
      expect(injected).toContain('[Previous Session Handoff]');
    });

    it('injected context includes [End Handoff] marker', () => {
      mockFreshHandoff();
      const input = createPromptInput();
      handoffInjector(input, testCtx);

      const injected = vi.mocked(outputPromptContext).mock.calls[0][0];
      expect(injected).toContain('[End Handoff');
    });

    it('injected context includes the HANDOFF.md body', () => {
      mockFreshHandoff(VALID_HANDOFF_CONTENT);
      const input = createPromptInput();
      handoffInjector(input, testCtx);

      const injected = vi.mocked(outputPromptContext).mock.calls[0][0];
      expect(injected).toContain('feat/my-feature');
    });

    it('returns result with continue: true after injection', () => {
      mockFreshHandoff();
      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      expect(result.continue).toBe(true);
    });
  });

  // -------------------------------------------------------------------------
  // File consumption (rename to .consumed)
  // -------------------------------------------------------------------------

  describe('file consumption', () => {
    it('renames HANDOFF.md to HANDOFF.md.consumed after injection', () => {
      mockFreshHandoff();
      const input = createPromptInput();
      handoffInjector(input, testCtx);

      expect(mockRenameSync).toHaveBeenCalledWith(HANDOFF_PATH, CONSUMED_PATH);
    });

    it('still injects context even when renameSync throws', () => {
      mockFreshHandoff();
      mockRenameSync.mockImplementation(() => { throw new Error('EACCES'); });

      const input = createPromptInput();
      const result = handoffInjector(input, testCtx);

      // Injection still happened
      expect(outputPromptContext).toHaveBeenCalled();
      expect(result.continue).toBe(true);
    });

    it('logs warning when rename fails', () => {
      mockFreshHandoff();
      mockRenameSync.mockImplementation(() => { throw new Error('rename failed'); });

      const input = createPromptInput();
      handoffInjector(input, testCtx);

      expect(testCtx.log).toHaveBeenCalledWith(
        'handoff-injector',
        expect.stringContaining('Could not rename'),
        'warn',
      );
    });
  });

  // -------------------------------------------------------------------------
  // Token budget truncation
  // -------------------------------------------------------------------------

  describe('token budget truncation', () => {
    it('truncates content when it exceeds MAX_TOKENS', () => {
      // Create content that will exceed MAX_TOKENS (600 tokens ~ 1800 chars)
      const longContent = `# Session Handoff\n${'word '.repeat(500)}`; // ~2500 chars
      mockFreshHandoff(longContent);

      const input = createPromptInput();
      handoffInjector(input, testCtx);

      const injected = vi.mocked(outputPromptContext).mock.calls[0][0];
      expect(injected).toContain('[...truncated for token budget]');
    });

    it('does not truncate short content', () => {
      mockFreshHandoff(VALID_HANDOFF_CONTENT); // ~300 chars, well under budget

      const input = createPromptInput();
      handoffInjector(input, testCtx);

      const injected = vi.mocked(outputPromptContext).mock.calls[0][0];
      expect(injected).not.toContain('[...truncated');
    });

    it('logs truncation when it occurs', () => {
      const longContent = `# Handoff\n${'x'.repeat(MAX_CHARS + 100)}`;
      mockFreshHandoff(longContent);

      const input = createPromptInput();
      handoffInjector(input, testCtx);

      expect(testCtx.log).toHaveBeenCalledWith(
        'handoff-injector',
        expect.stringContaining('Truncated'),
      );
    });
  });

  // -------------------------------------------------------------------------
  // project_dir resolution
  // -------------------------------------------------------------------------

  describe('project_dir resolution', () => {
    it('uses project_dir from input when provided', () => {
      mockExistsSync.mockImplementation((p: string) => {
        return p === '/custom/project/.claude/HANDOFF.md';
      });
      mockStatSync.mockReturnValue({ mtimeMs: Date.now() - 1000 });
      mockReadFileSync.mockReturnValue(VALID_HANDOFF_CONTENT);

      const input = createPromptInput({ project_dir: '/custom/project' });
      handoffInjector(input, testCtx);

      expect(mockExistsSync).toHaveBeenCalledWith('/custom/project/.claude/HANDOFF.md');
    });

    it('falls back to getProjectDir when project_dir is absent', () => {
      mockExistsSync.mockImplementation((p: string) => {
        return p === '/test/project/.claude/HANDOFF.md';
      });
      mockStatSync.mockReturnValue({ mtimeMs: Date.now() - 1000 });
      mockReadFileSync.mockReturnValue(VALID_HANDOFF_CONTENT);

      const input = createPromptInput({ project_dir: undefined });
      handoffInjector(input, testCtx);

      expect(mockExistsSync).toHaveBeenCalledWith('/test/project/.claude/HANDOFF.md');
    });
  });
});
